import React, { useEffect, useState } from 'react';
import { X, Compass } from 'lucide-react';
import './NodeInfoModal.css';
import { resolveAvatarSrc } from '../../app/appShared';
import { useUserCard } from '../social/UserCardContext';
import { SENSE_ARTICLE_ENTRY_LABEL } from '../senseArticle/senseArticleUi';

const getUserId = (user) => {
    if (!user) return '';
    return user._id?.toString?.() || user._id || user.id || '';
};

const formatCreatedAt = (createdAt) => {
    if (!createdAt) return '未知';
    const date = new Date(createdAt);
    if (Number.isNaN(date.getTime())) return '未知';
    return date.toLocaleString('zh-CN', { hour12: false });
};

const getUserAlliance = (user) => {
    const alliance = user?.alliance || user?.allianceId;
    if (!alliance || typeof alliance !== 'object') return null;
    const name = typeof alliance.name === 'string' ? alliance.name.trim() : '';
    const flag = typeof alliance.flag === 'string' ? alliance.flag.trim() : '';
    if (!name && !flag) return null;
    return { name, flag };
};

const getNodePrimarySense = (node) => {
    const senses = Array.isArray(node?.synonymSenses) ? node.synonymSenses : [];
    if (typeof node?.activeSenseId === 'string' && node.activeSenseId.trim()) {
        const matched = senses.find((item) => item?.senseId === node.activeSenseId.trim());
        if (matched) return matched;
    }
    return senses[0] || null;
};

const getNodeDisplayName = (node) => {
    if (typeof node?.displayName === 'string' && node.displayName.trim()) return node.displayName.trim();
    const name = typeof node?.name === 'string' ? node.name.trim() : '';
    const senseTitle = typeof node?.activeSenseTitle === 'string' && node.activeSenseTitle.trim()
        ? node.activeSenseTitle.trim()
        : (typeof getNodePrimarySense(node)?.title === 'string' ? getNodePrimarySense(node).title.trim() : '');
    return senseTitle ? `${name}-${senseTitle}` : (name || '未命名知识域');
};

const getNodeSenseTitle = (node) => {
    if (typeof node?.activeSenseTitle === 'string' && node.activeSenseTitle.trim()) return node.activeSenseTitle.trim();
    const sense = getNodePrimarySense(node);
    return typeof sense?.title === 'string' ? sense.title.trim() : '';
};

const getNodeSenseSummary = (node) => {
    if (typeof node?.knowledge === 'string' && node.knowledge.trim()) return node.knowledge.trim();
    if (typeof node?.description === 'string' && node.description.trim()) return node.description.trim();
    return '';
};

const UserAvatar = ({ user, isMaster = false, fallbackKey = '', onOpenUserCard }) => {
    const username = user?.username || '未知用户';
    const alliance = getUserAlliance(user);
    const tooltip = alliance?.name ? `【${alliance.name}】${username}` : username;
    return (
        <button
            type="button"
            key={getUserId(user) || fallbackKey}
            className={`user-avatar-item ${isMaster ? 'is-master' : ''}`}
            title={tooltip}
            onClick={(event) => onOpenUserCard?.(user, event)}
        >
            <img
                src={resolveAvatarSrc(user?.avatar)}
                alt={tooltip}
                className="user-avatar-img"
            />
            {alliance?.flag && (
                <span
                    className="user-avatar-alliance-flag"
                    style={{ backgroundColor: alliance.flag }}
                    aria-label={alliance.name ? `熵盟：${alliance.name}` : '熵盟旗帜'}
                />
            )}
            <span className="user-avatar-tooltip">{tooltip}</span>
        </button>
    );
};

const NodeInfoModal = ({
    isOpen,
    onClose,
    nodeDetail,
    onEnterKnowledgeDomain,
    onOpenSenseArticle,
    simpleOnly = false,
    canApplyDomainMaster = false,
    isApplyingDomainMaster = false,
    onApplyDomainMaster
}) => {
    const [showApplyForm, setShowApplyForm] = useState(false);
    const [applyReason, setApplyReason] = useState('');
    const { openUserCard } = useUserCard();

    useEffect(() => {
        if (!isOpen) {
            setShowApplyForm(false);
            setApplyReason('');
        }
    }, [isOpen, nodeDetail?._id]);

    if (!isOpen || !nodeDetail) return null;

    const nodeSenseTitle = getNodeSenseTitle(nodeDetail);
    const nodeSenseSummary = getNodeSenseSummary(nodeDetail);
    if (simpleOnly) {
        return (
            <div className="modal-backdrop" onClick={onClose}>
                <div className="modal-content node-info-modal" onClick={(e) => e.stopPropagation()}>
                    <div className="modal-header">
                        <h2>词条详情</h2>
                        <button className="btn-close" onClick={onClose}>
                            <X size={24} />
                        </button>
                    </div>
                    <div className="modal-body">
                        <div className="node-info-section">
                            <h3 className="info-section-title">{getNodeDisplayName(nodeDetail)}</h3>
                            {nodeSenseTitle && (
                                <p className="info-section-desc">释义题目：{nodeSenseTitle}</p>
                            )}
                            {nodeSenseSummary && (
                                <p className="info-section-desc">概述：{nodeSenseSummary}</p>
                            )}
                        </div>
                    </div>
                    <div className="modal-footer">
                        <button
                            className="btn btn-primary"
                            onClick={() => onOpenSenseArticle && onOpenSenseArticle(nodeDetail)}
                        >
                            {SENSE_ARTICLE_ENTRY_LABEL}
                        </button>
                        <button className="btn btn-secondary" onClick={onClose}>关闭</button>
                    </div>
                </div>
            </div>
        );
    }

    const creator = nodeDetail.owner || null;
    const domainMaster = nodeDetail.domainMaster ? [nodeDetail.domainMaster] : [];
    const domainMasterId = getUserId(nodeDetail.domainMaster);
    const admins = Array.isArray(nodeDetail.domainAdmins)
        ? nodeDetail.domainAdmins
            .filter(Boolean)
            .filter((admin, index, arr) => {
                const adminId = getUserId(admin);
                if (!adminId) return true;
                if (adminId === domainMasterId) return false;
                return arr.findIndex((candidate) => getUserId(candidate) === adminId) === index;
            })
        : [];

    const handleSubmitApply = async () => {
        const reason = applyReason.trim();
        if (!reason) {
            window.alert('请填写申请理由');
            return;
        }
        if (!onApplyDomainMaster) return;

        const success = await onApplyDomainMaster(reason);
        if (success) {
            setShowApplyForm(false);
            setApplyReason('');
        }
    };

    return (
        <div className="modal-backdrop" onClick={onClose}>
            <div className="modal-content node-info-modal" onClick={(e) => e.stopPropagation()}>
                <div className="modal-header">
                    <h2>知识域详细信息</h2>
                    <button
                        className="btn-close"
                        onClick={onClose}
                    >
                        <X size={24} />
                    </button>
                </div>

                <div className="modal-body">
                    <div className="node-info-section">
                        <h3 className="info-section-title">{getNodeDisplayName(nodeDetail)}</h3>
                        {nodeDetail.description && (
                            <p className="info-section-desc">概述：{nodeDetail.description}</p>
                        )}
                        {nodeSenseTitle && (
                            <p className="info-section-desc">当前释义：{nodeSenseTitle}</p>
                        )}
                        {nodeSenseSummary && (
                            <p className="info-section-desc">概述：{nodeSenseSummary}</p>
                        )}
                    </div>

                    <div className="node-user-sections">
                        <div className="user-group-section">
                            <h4 className="user-group-title">创建者</h4>
                            <div className="creator-row">
                                {creator ? (
                                    <div className="user-avatar-list">
                                        <UserAvatar user={creator} fallbackKey="creator" onOpenUserCard={openUserCard} />
                                    </div>
                                ) : (
                                    <div className="user-group-empty">暂无</div>
                                )}
                                <div className="creator-meta">
                                    <span className="creator-meta-label">创建时间：</span>
                                    <span className="creator-meta-value">{formatCreatedAt(nodeDetail.createdAt)}</span>
                                </div>
                            </div>
                        </div>

                        <div className="user-group-section">
                            <h4 className="user-group-title">管理者</h4>
                            {domainMaster.length > 0 || admins.length > 0 ? (
                                <div className="user-avatar-list manager-avatar-list">
                                    {domainMaster.length > 0 && (
                                        <UserAvatar
                                            user={domainMaster[0]}
                                            isMaster
                                            fallbackKey="domain-master"
                                            onOpenUserCard={openUserCard}
                                        />
                                    )}
                                    {admins.map((admin, index) => (
                                        <UserAvatar
                                            key={getUserId(admin) || `admin-${index}`}
                                            user={admin}
                                            fallbackKey={`admin-${index}`}
                                            onOpenUserCard={openUserCard}
                                        />
                                    ))}
                                </div>
                            ) : (
                                <div className="user-group-empty">暂无管理者</div>
                            )}
                        </div>
                    </div>

                    {canApplyDomainMaster && (
                        <div className="domain-master-apply-section">
                            {!showApplyForm ? (
                                <button
                                    type="button"
                                    className="btn btn-blue domain-master-apply-open-btn"
                                    onClick={() => setShowApplyForm(true)}
                                >
                                    申请成为域主
                                </button>
                            ) : (
                                <div className="domain-master-apply-form">
                                    <label className="domain-master-apply-label">申请理由</label>
                                    <textarea
                                        className="domain-master-apply-textarea"
                                        value={applyReason}
                                        maxLength={300}
                                        placeholder="请填写你申请成为该知识域域主的理由（最多300字）"
                                        onChange={(event) => setApplyReason(event.target.value)}
                                    />
                                    <div className="domain-master-apply-counter">
                                        {applyReason.trim().length}/300
                                    </div>
                                    <div className="domain-master-apply-actions">
                                        <button
                                            type="button"
                                            className="btn btn-small btn-success"
                                            onClick={handleSubmitApply}
                                            disabled={isApplyingDomainMaster}
                                        >
                                            {isApplyingDomainMaster ? '提交中...' : '提交申请'}
                                        </button>
                                        <button
                                            type="button"
                                            className="btn btn-small btn-secondary"
                                            onClick={() => setShowApplyForm(false)}
                                            disabled={isApplyingDomainMaster}
                                        >
                                            取消
                                        </button>
                                    </div>
                                </div>
                            )}
                        </div>
                    )}
                </div>

                <div className="modal-footer">
                    <button
                        className="btn btn-primary enter-domain-btn"
                        onClick={() => onEnterKnowledgeDomain && onEnterKnowledgeDomain(nodeDetail)}
                    >
                        <Compass size={18} />
                        进入知识域
                    </button>
                    <button
                        className="btn btn-blue"
                        onClick={() => onOpenSenseArticle && onOpenSenseArticle(nodeDetail)}
                    >
                        {SENSE_ARTICLE_ENTRY_LABEL}
                    </button>
                    <button
                        className="btn btn-secondary"
                        onClick={onClose}
                    >
                        关闭
                    </button>
                </div>
            </div>
        </div>
    );
};

export default NodeInfoModal;
